VALUES
  ('retired-d0d1b9a2-moex-00190', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X1 年度相關資料如下：本期淨利$550,000，所得稅費用$30,000，利息費用$5,000， 處分機器損失$30,000，折舊費用$25,000，應收帳款增加$30,000，存貨增加$10,000，應付帳 款增加$20,000，預付費用增加$22,000，應付利息增加$8,000，本期所得稅負債增加$6,000， 根據上述資料，甲公司X1年度營運產生之現金流量為何？ $538,000  $590,000  $598,000  $606,000', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00191', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司採確定福利退休計畫，X1年初確定福利義務現值為$800,000，計畫資產公允價值為 $550,000，X1當期服務成本為$80,000，折現率7%，計畫資產實際報酬為$50,000，精算損失 $18,000，提撥退休基金$250,000，支付退休金$188,000，則甲公司 X1 年度應認列之退休金 費用與其他綜合損益之金額各為多少？ $87,500，認列於其他綜合損失為$12,000 $97,500，認列於其他綜合損失為$6,500 $87,500，認列於其他綜合損失為$18,000 $97,500，認列於其他綜合損失為$18,000', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00192', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司為設備製造商，甲公司於X1年1月1日出租一台機器給乙公司，租期5年之不可取消租 賃協議；每年期初支付租金$200,000，租期屆滿應返還甲公司。該設備耐用年限5年，租期屆滿 估計殘值為$200,000，乙公司保證殘值為$150,000，該設備公允價值為$1,020,039，製造成本為 $700,000。為簽訂該租賃合約，甲公司發生租賃原始直接成本$9,969。該租約隱含利率與市場利 率皆為7%。請問甲公司X1年度針對該項租賃合約應認列之銷貨收入及銷貨毛利各為多少？ （註：複利現值因子；i=7%，5期為0.712986） $1,020,039及銷貨毛利$320,039 $984,390及銷貨毛利$320,039 $1,010,070及銷貨毛利$310,070 $1,020,039及銷貨毛利$310,070', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00193', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司為一家航空公司，於X1年10月1日獲得政府贈與臺北往返香港之飛航證書，當時 該證書之公允價值為$6,750,000，有效期限為5年。期滿能持續以少許成本申請換發新執 照，更新期限仍為5年。在可預見的未來，臺北往返香港之飛航服務並不預期會被其他服 務所取代。X4 年初主管機關決定飛航證書不採申請換發，而採競標方式。X4 年甲公司評 估該飛航證書並未發生價值減損，試計算X4年度之攤銷費用。 $1,012,500  $1,350,500  $3,000,000  $3,375,000', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00194', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年度報表中顯示流動資產項目僅有現金、應收帳款、存貨與預付費用4項。流動 比率為 3.5，速動比率為 2.0。若該公司 X2 年底能以現金$200,000 之價格出售一批毛利率', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00195', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '3%的商品，則可將流動比率提高為4.0。若該毛利率係以銷貨成本為分母，則甲公司於X2 年底出售該批商品後的速動比率為何？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00196', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '50  4.00  5.33  9.01', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00197', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["今天氣溫驟降，乍暖還寒，他雖已穿上外套，仍然覺得「不寒而慄」", "疫情趨緩，管制措施取消，週末遊樂場重新開放，人潮「不絕如縷」", "全面網路教學，不像在教室上課，老師可以直接對學生「移樽就教」", "網路上有各種消息與傳聞，需仔細辨明查證，是否只是「空穴來風」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00198', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「近代民族國家的形成，無疑促進了各國（特別是各小國）從過去歷史中去尋求民 族文化及其經典系列的努力。能夠尋找出這樣一個系列，並且讓世界各國接受與承 認，無疑可以增進民族的尊嚴與自豪。近代所形成的各級教育體系，也促進了這種 作用。各國在語言教育及人文教育中，都會把經典作品按其程度的深淺，選入各級 教育的教材中，以便讓他們的人民，學習到這一『傳統』，從『認識』中得到『認 同』，並由此而獲得『民族感情』。」 根據上文，下列敘述何者最符合作者立論？', '["一個民族國家的人文經典，時常需要從歷史中找尋，同時透過後天教育體制來發 展與建構", "近代民族國家的形成，需要受到世界各國的接受與承認，所以吸收西方思想與方 法是必要的歷程", "民族感情跟民族認同有關，民族認同又與傳統有關，因此應該積極地講究復古， 因為復古即傳統", "各級教育有形塑民族人文經典的功能，因此尚未成熟的作品，基於保護和提攜， 還是應該選入教材"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00199', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「李漁說南方人吃切麵，把油鹽醬醋等作料，都下到麵湯裡，他對這種吃麵的辦法 期期以為不可，『湯有味而麵無味，是人所重者不在麵而在湯，與未嘗食麵等也。 予則不然，以調和諸物，盡歸於麵，麵具五味而湯獨清，如此方是食麵，非飲湯也。』 李漁自製『五香麵』，所謂的『五香』是醬、醋、椒末、芝麻屑，另加上焯筍或煮 蕈煮蝦的高湯；椒末、芝麻屑拌入麵裡，醬、醋、高湯作為和麵之水，拌勻，揉薄， 切細，如此一來美味盡在麵條之中。」 根據上文，符合李漁製麵的態度是：', '["煮湯麵時的調味越多樣越好", "油鹽醬醋的比例可隨性任意", "湯麵的關鍵在高湯，需精燉熬湯", "作麵時需調和醬料高湯和入麵中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
